import { useQuery } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { MapPin, Upload } from "lucide-react";
import { Link } from "wouter";
import { useIsMobile } from "@/hooks/use-mobile";
import { useEffect, useState } from "react";
import sdk from "@farcaster/frame-sdk";

interface Stats {
  totalNFTs: number;
  totalVolume: string;
  totalHolders: number;
}

export default function Landing() {
  const isMobile = useIsMobile();
  const [addMiniAppPrompted, setAddMiniAppPrompted] = useState(false);

  const { data: stats } = useQuery<Stats>({
    queryKey: ["/api/stats"],
  });

  const formatVolume = (volume: string) => {
    return parseFloat(volume).toFixed(1);
  };

  // Prompt user to add Mini App (Base App)
  useEffect(() => {
    const promptAddMiniApp = async () => {
      // Check if we're in a Farcaster/Base App environment
      if (typeof window === 'undefined' || !sdk?.actions?.addMiniApp) {
        return;
      }

      // Check if user has already been prompted (this session)
      if (addMiniAppPrompted) {
        return;
      }

      // Check localStorage to avoid re-prompting on every load
      const hasSeenPrompt = localStorage.getItem('travelmint_miniapp_prompted');
      if (hasSeenPrompt === 'true') {
        return;
      }

      try {
        console.log('🎯 Prompting user to add TravelMint Mini App...');

        // Show the "Add Mini App" pop-up
        const response = await sdk.actions.addMiniApp();

        if (response.notificationDetails) {
          console.log('✅ Mini App added with notifications enabled!');
        } else {
          console.log('✅ Mini App added without notifications');
        }

        // Mark as prompted to avoid showing again
        localStorage.setItem('travelmint_miniapp_prompted', 'true');
        setAddMiniAppPrompted(true);
      } catch (error) {
        console.log('⚠️ Add Mini App prompt error (user may have skipped):', error);
        // Still mark as prompted even if user skipped
        localStorage.setItem('travelmint_miniapp_prompted', 'true');
        setAddMiniAppPrompted(true);
      }
    };

    // Delay slightly to ensure SDK is ready
    const timer = setTimeout(promptAddMiniApp, 500);
    return () => clearTimeout(timer);
  }, [addMiniAppPrompted]);

  // Lock scroll on mount, unlock on unmount
  useEffect(() => {
    const { documentElement: html, body } = document;
    const prevHtmlOverflow = html.style.overflow;
    const prevBodyOverflow = body.style.overflow;

    // Lock html and body overflow
    html.style.overflow = 'hidden';
    body.style.overflow = 'hidden';

    // iOS robustness: prevent rubber-band scrolling
    const prevPosition = body.style.position;
    const prevTop = body.style.top;
    const scrollY = window.scrollY;

    body.style.position = 'fixed';
    body.style.top = `-${scrollY}px`;
    body.style.width = '100%';

    return () => {
      // Restore previous values
      html.style.overflow = prevHtmlOverflow;
      body.style.overflow = prevBodyOverflow;
      body.style.position = prevPosition;
      body.style.top = prevTop;
      body.style.width = '';
      window.scrollTo(0, scrollY);
    };
  }, []);

  return (
    <div className={`h-screen max-h-screen overflow-hidden bg-background ${isMobile ? 'pb-14' : ''}`} style={{ touchAction: 'none', overscrollBehavior: 'none' }}>
      {/* Hero Section */}
      <section className="relative overflow-hidden flex-1 flex flex-col justify-center">
        <div className="absolute inset-0 bg-gradient-to-br from-primary/10 via-accent/5 to-background"></div>
        <div className="relative container mx-auto px-4 py-4">
          <div className="text-center max-w-4xl mx-auto">
            <h1 className="text-2xl md:text-4xl font-bold mb-3 leading-tight" style={{ color: '#0000ff' }}>
              TravelMint
            </h1>
            <p className="text-sm md:text-base text-muted-foreground mb-4 max-w-2xl mx-auto">
              Mint your travel photography as NFTs, pin them to locations worldwide, and trade with fellow explorers.
            </p>
            <div className="flex flex-col sm:flex-row gap-3 justify-center">
              <Link href="/mint">
                <Button 
                  size="default" 
                  className="bg-primary hover:bg-primary/90 text-primary-foreground px-6 py-2"
                  data-testid="mint-memory-button"
                >
                  <Upload className="w-4 h-4 mr-2" />
                  Mint your Memory
                </Button>
              </Link>
              <Link href="/explore">
                <Button 
                  variant="outline" 
                  size="default" 
                  className="px-6 py-2"
                  data-testid="explore-map-button"
                >
                  <MapPin className="w-4 h-4 mr-2" />
                  Explore Map
                </Button>
              </Link>
            </div>
          </div>
        </div>
      </section>

      {/* Statistics Section */}
      <section className="py-4 bg-muted/50">
        <div className="container mx-auto px-4">
          <div className="grid grid-cols-2 gap-6 max-w-lg mx-auto">
            <div className="text-center">
              <div className="text-xl md:text-3xl font-bold mb-1" style={{ color: '#ffffff' }} data-testid="stats-nfts">
                {stats?.totalNFTs || 0}
              </div>
              <div className="text-xs text-muted-foreground">NFTs Minted</div>
            </div>

            <div className="text-center">
              <div className="text-xl md:text-3xl font-bold text-accent mb-1" data-testid="stats-holders">
                {stats?.totalHolders || 0}
              </div>
              <div className="text-xs text-muted-foreground">Holders</div>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
}

