                    </button>
                  </div>

                  {/* Buy Button (if for sale) */}
                  {nftDetails.isForSale === 1 && (
                    <div className="flex items-center justify-between p-4 bg-muted rounded-lg">
                      <div>
                        <p className="text-sm text-muted-foreground">Price</p>
