        isHolder,
        queryCount,
        remainingFreeQueries,
        hasAccess,
        freeQueryLimit: FREE_QUERY_LIMIT
      });
    } catch (error: any) {
      console.error('Travel AI status error:', error);
      res.status(500).json({ error: 'Failed to get status' });
    }
  });

  // POST /api/travel-ai/chat - Chat with Travel AI (3 free queries per day for non-holders)
  app.post("/api/travel-ai/chat", async (req: Request, res: Response) => {
    try {
      const { message, walletAddress, chatHistory } = req.body;

      if (!message || typeof message !== 'string') {
        return res.status(400).json({ error: 'Message is required' });
      }

      if (!walletAddress) {
        return res.status(400).json({ error: 'Wallet address is required' });
      }

      // Validate chat history format (for conversation continuity)
      const validHistory = Array.isArray(chatHistory) ? chatHistory.filter(
        (msg: any) => msg && typeof msg.role === 'string' && typeof msg.content === 'string'
      ) : [];

      const normalizedAddress = walletAddress.toLowerCase();
      const today = getTodayDateString();

      // Check holder status
      const isHolder = await isNFTHolder(walletAddress);

      // Get current query count and last query date
      const result = await db.execute(sql`
        SELECT query_count, last_query_date FROM travel_ai_queries 
        WHERE wallet_address = ${normalizedAddress}
      `);

      let currentCount = 0;
      if (result.rows.length > 0) {
        const lastQueryDate = result.rows[0].last_query_date as string | null;
        // If last query was on a different day, count is reset to 0
        if (lastQueryDate === today) {
          currentCount = Number(result.rows[0].query_count);
        }
      }

      // Check access - holders have unlimited, non-holders get 3 free per day
      if (!isHolder && currentCount >= FREE_QUERY_LIMIT) {
        return res.status(403).json({ 
          error: 'Daily limit reached. Mint a TravelMint NFT for unlimited access, or come back tomorrow!',
          queryCount: currentCount,
          remainingFreeQueries: 0
        });
      }

      // Import and call OpenRouter service with chat history for context
      const { getTravelRecommendation } = await import('./openrouter-service');
      const textResponse = await getTravelRecommendation(message, validHistory);

      // Extract place names from bold text (**Place Name**) and fetch Wikipedia images
      const { getWikipediaInfo } = await import('./wikipedia-service');
      const boldMatches = textResponse.match(/\*\*([^*]+)\*\*/g) || [];
      const placeNames = boldMatches
        .map(m => m.replace(/\*\*/g, ''))
        .filter(name => !name.includes('Attractions') && !name.includes('Cafes') && !name.includes('Restaurants') && !name.includes('Sites') && name.length < 50)
        .slice(0, 3); // Limit to 3 places to keep it fast

      // Fetch images in parallel (non-blocking, best effort)
      const imagePromises = placeNames.map(async (name) => {
        try {
          const info = await getWikipediaInfo(name);
          return info ? { name, ...info } : null;
        } catch {
          return null;
        }
      });

      const imageResults = await Promise.allSettled(imagePromises);
      const images = imageResults
        .filter((r): r is PromiseFulfilledResult<any> => r.status === 'fulfilled' && r.value !== null)
        .map(r => r.value);

      const response = textResponse;

      // Increment query count for non-holders with daily reset logic
      if (!isHolder) {
        await db.execute(sql`
          INSERT INTO travel_ai_queries (wallet_address, query_count, last_query_date, updated_at)
          VALUES (${normalizedAddress}, 1, ${today}, NOW())
          ON CONFLICT (wallet_address) 
          DO UPDATE SET 
            query_count = CASE 
              WHEN travel_ai_queries.last_query_date = ${today} 
              THEN travel_ai_queries.query_count + 1 
              ELSE 1 
            END,
            last_query_date = ${today},
            updated_at = NOW()
        `);
      }

      const newCount = isHolder ? currentCount : currentCount + 1;
      const remainingFreeQueries = isHolder ? -1 : Math.max(0, FREE_QUERY_LIMIT - newCount);

      res.json({ 
        success: true,
        response,
        images, // Wikipedia images for mentioned places
        isHolder,
        queryCount: newCount,
        remainingFreeQueries
      });
    } catch (error: any) {
      console.error('Travel AI chat error:', error);

      // Handle rate limit errors gracefully
      const errorMessage = error.message || '';
      if (errorMessage.includes('429') || errorMessage.includes('RESOURCE_EXHAUSTED') || errorMessage.includes('quota')) {
        return res.status(429).json({ 
          error: 'AI service is temporarily busy. Please try again in a few moments.',
          retryable: true
        });
      }

      res.status(500).json({ 
        error: 'Failed to get travel advice. Please try again.',
        message: error.message 
      });
    }
  });

  return createServer(app);
}

