import { createConfig, http } from 'wagmi'
import { base, mainnet, baseSepolia } from 'wagmi/chains'
import { coinbaseWallet, walletConnect, injected } from 'wagmi/connectors'
import { farcasterMiniApp as miniAppConnector } from '@farcaster/miniapp-wagmi-connector'
import { Attribution } from 'ox/erc8021'

const DATA_SUFFIX = Attribution.toDataSuffix({
  codes: ['bc_x25appl2'],
})

// Get the correct app URL for wallet authorization
const getAppUrl = () => {
  // Use current origin in development, production domain for production
  if (typeof window !== 'undefined') {
    // Development: use current origin to fix CORS issues
    if (window.location.hostname.includes('replit.dev') || window.location.hostname.includes('replit.co')) {
      return window.location.origin;
    }
  }
  // Production: use production domain
  return 'https://travelnft.replit.app';
};

// Manual connection config - no auto-connect to prevent Farcaster crashes
export const config = createConfig({
  chains: [base, mainnet, baseSepolia],
  connectors: [
    miniAppConnector(), // Native Farcaster Mini App connector
    injected({
      shimDisconnect: true,
    }),
    walletConnect({
      projectId: import.meta.env.VITE_WALLETCONNECT_PROJECT_ID || '',
      metadata: {
        name: 'TravelMint',
        description: 'Travel Photo NFT Marketplace on Base',
        url: getAppUrl(),
        icons: [`${getAppUrl()}/icon-192x192.png`],
      },
      showQrModal: true,
    }),
    coinbaseWallet({
      appName: 'TravelMint',
      appLogoUrl: `${getAppUrl()}/icon-192x192.png`,
      preference: 'all', // Support both smart wallet and EOA
      version: '4',
    }),
  ],
  transports: {
    [base.id]: http('https://mainnet.base.org', {
      timeout: 10000, // 10 second timeout
    }),
    [mainnet.id]: http('https://cloudflare-eth.com', {
      timeout: 10000, // 10 second timeout
    }),
    [baseSepolia.id]: http('https://sepolia.base.org', {
      timeout: 10000, // 10 second timeout
    }),
  },
  // Disable auto-connect to prevent crashes in iframe environments
  multiInjectedProviderDiscovery: false,
  syncConnectedChain: false,
  ssr: false,
  dataSuffix: DATA_SUFFIX,
})

shared/ipfs.ts.content:
// IPFS utilities for TravelMint
// Shared between client and server

export interface IPFSUploadResponse {
  IpfsHash: string;
  PinSize: number;
  Timestamp: string;
}

export interface NFTMetadata {
  name: string;
  description: string;
  image: string; // IPFS URL
  attributes: Array<{
    trait_type: string;
    value: string;
  }>;
  external_url?: string;
  location?: {
    city: string;
    latitude: string;
    longitude: string;
  };
}

export function createNFTMetadata(params: {
  title: string;
  description: string;
  imageIpfsUrl: string;
  category: string;
  location: {
    city: string;
    latitude: string;
    longitude: string;
  };
}): NFTMetadata {
  return {
    name: params.title,
    description: params.description || "Travel NFT minted on TravelMint",
    image: params.imageIpfsUrl,
    attributes: [
      { trait_type: "Category", value: params.category },
      { trait_type: "Location", value: params.location.city },
      { trait_type: "Latitude", value: params.location.latitude },
      { trait_type: "Longitude", value: params.location.longitude },
      { trait_type: "Minted Date", value: new Date().toISOString() },
      { trait_type: "Platform", value: "TravelMint" }
    ],
    external_url: "https://travelmint.app",
    location: params.location
  };
}

export function createIPFSUrl(hash: string): string {
  // Try to use dedicated gateway if available, fallback to faster alternatives
  const gateway = process.env.PINATA_GATEWAY;
  if (gateway && typeof window === 'undefined') {
    // Server-side: use dedicated gateway if configured
    return `https://${gateway}/ipfs/${hash}`;
  }
  // Use alternative fast gateway instead of rate-limited Pinata public gateway
  return `https://ipfs.io/ipfs/${hash}`;
}

export function extractIPFSHash(ipfsUrl: string): string {
  // Extract hash from various IPFS URL formats
  if (ipfsUrl.includes('gateway.pinata.cloud/ipfs/')) {
    return ipfsUrl.split('gateway.pinata.cloud/ipfs/')[1];
  }
  if (ipfsUrl.includes('ipfs://')) {
    return ipfsUrl.replace('ipfs://', '');
  }
  if (ipfsUrl.startsWith('Qm') || ipfsUrl.startsWith('baf')) {
    return ipfsUrl;
  }
  throw new Error('Invalid IPFS URL format');
}

