    setPendingCheckInPOI(poi);

    const data = encodeFunctionData({
      abi: QUEST_ABI,
      functionName: 'completeQuest',
      args: [BigInt(CHECK_IN_QUEST_ID)]
    });

    console.log("Sending transaction to QuestManager...");
    sendTransaction({
      to: QUEST_MANAGER_ADDRESS,
