                category,
                metadataUrl
              ]
            })
          }
        ];
      }

      // 🚀 REAL BLOCKCHAIN: Execute batch transaction
      console.log('⚡ STARTING REAL BLOCKCHAIN MINT...');

      await sendCalls({
        calls: batchCalls
      });

      console.log('✅ Blockchain transaction batch sent with metadata!');
      console.log('⏳ Waiting for transaction confirmation...');

