import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const badgeVariants = cva(
  "inline-flex items-center rounded-full border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2",
  {
    variants: {
      variant: {
        default:
          "border-transparent bg-primary text-primary-foreground hover:bg-primary/80",
        secondary:
          "border-transparent bg-secondary text-secondary-foreground hover:bg-secondary/80",
        destructive:
          "border-transparent bg-destructive text-destructive-foreground hover:bg-destructive/80",
        outline: "text-foreground",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  }
)

export interface BadgeProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof badgeVariants> {}

function Badge({ className, variant, ...props }: BadgeProps) {
  return (
    <div className={cn(badgeVariants({ variant }), className)} {...props} />
  )
}

export { Badge, badgeVariants }

client/src/App.tsx.content:
import { Switch, Route, useLocation } from "wouter";
import { queryClient } from "./lib/queryClient";
import { QueryClientProvider } from "@tanstack/react-query";
import { Toaster } from "@/components/ui/toaster";
import { TooltipProvider } from "@/components/ui/tooltip";
import { WalletProvider } from "@/contexts/wallet-provider";
import { FarcasterAuthProvider } from "@/contexts/farcaster-auth-provider";
import { useEffect, useState, Component, ReactNode } from "react";
import sdk from "@farcaster/frame-sdk";
import Explore from "@/pages/explore";
import Marketplace from "@/pages/marketplace";
import MyNFTs from "@/pages/my-nfts";
import Mint from "@/pages/mint";
import Quests from "@/pages/quests";
import Leaderboard from "@/pages/leaderboard";
import Privacy from "@/pages/privacy";
import AdminNotifications from "@/pages/admin-notifications";
import Faq from "@/pages/faq";
import About from "@/pages/about";
import Contact from "@/pages/contact";
import NFTDetail from "@/pages/nft-detail";
import Badges from "@/pages/badges";
import TravelAI from "@/pages/travel-ai";
import Navigation from "@/components/navigation";

// Browser-safe Farcaster SDK initialization
let farcasterReady = false;
if (typeof window !== 'undefined' && sdk?.actions?.ready) {
  console.log('🚀 Initializing Farcaster SDK...');
  try {
    // Call ready() without await to prevent blocking
    sdk.actions.ready();
    farcasterReady = true;
    console.log('✅ Farcaster ready signal sent');
  } catch (e) {
    console.log('⚠️ Farcaster not available (running in web browser)');
  }
}

interface ErrorBoundaryState {
  hasError: boolean;
}

class ErrorBoundary extends Component<{children: ReactNode}, ErrorBoundaryState> {
  constructor(props: {children: ReactNode}) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(): ErrorBoundaryState {
    return { hasError: true };
  }

  componentDidCatch(error: Error, errorInfo: any) {
    console.error('🚨 CRITICAL: Error caught by boundary:', error);
    console.error('🚨 Error message:', error.message);
    console.error('🚨 Error stack:', error.stack);
    console.error('🚨 Component stack:', errorInfo.componentStack);

    // Send error details to console for debugging
    if (typeof window !== 'undefined') {
      (window as any).lastError = { error, errorInfo };
    }
  }

  render() {
    if (this.state.hasError) {
      return (
        <div style={{ 
          minHeight: '100vh', 
          display: 'flex', 
          alignItems: 'center', 
          justifyContent: 'center',
          backgroundColor: '#0f172a',
          color: 'white',
          fontFamily: 'system-ui, sans-serif'
        }}>
          <div style={{ textAlign: 'center', padding: '2rem' }}>
            <h1 style={{ fontSize: '1.5rem', fontWeight: 'bold', marginBottom: '1rem' }}>
              TravelMint Error
            </h1>
            <p style={{ marginBottom: '1rem', opacity: 0.8 }}>
              App crashed in Farcaster environment
            </p>
            <button 
              onClick={() => window.location.reload()}
              style={{
                backgroundColor: '#3b82f6',
                color: 'white',
                padding: '0.5rem 1rem',
                borderRadius: '0.375rem',
                border: 'none',
                cursor: 'pointer'
              }}
            >
              Reload App
            </button>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

function DeepLinkHandler() {
  const [, setLocation] = useLocation();

  useEffect(() => {
    const handleDeepLink = async () => {
      try {
        // Check Farcaster SDK context for deep link URL
        if (typeof window !== 'undefined' && sdk?.context) {
          const context = await Promise.resolve(sdk.context);

          // Farcaster provides the launch URL via context.location
          // Use type assertion as location structure varies
          const location = context?.location as { url?: string; pathname?: string } | undefined;

          if (location) {
            // Try pathname first, then parse from url
            let pathname = location.pathname;
            if (!pathname && location.url) {
              try {
                const url = new URL(location.url);
                pathname = url.pathname;
              } catch (e) {
                console.log('⚠️ Failed to parse location URL');
              }
            }

            if (pathname) {
              console.log('🔗 Farcaster deep link detected:', pathname);

              // Handle /nft/:tokenId deep link
              if (pathname.startsWith('/nft/')) {
                console.log('📍 Navigating to NFT detail:', pathname);
                setLocation(pathname);
                return;
              }
            }
          }
        }

        // Also check browser URL for /nft/:tokenId (for direct browser access)
        const currentPath = window.location.pathname;
        if (currentPath.startsWith('/nft/')) {
          console.log('🔗 Direct NFT URL access:', currentPath);
          // Already at the right path, wouter will handle it
        }
      } catch (error) {
        console.log('⚠️ Deep link check failed:', error);
      }
    };

    handleDeepLink();
  }, [setLocation]);

  return null;
}

function ReferralHandler() {
  const [, setLocation] = useLocation();

  useEffect(() => {
    // Check for referral code in URL path (/r/CODE)
    const path = window.location.pathname;
    const pathMatch = path.match(/^\/r\/([A-Z0-9]+)$/i);

    if (pathMatch) {
      const referralCode = pathMatch[1];
      console.log('🎁 Referral code captured from path:', referralCode);

      // Store in localStorage
      localStorage.setItem('pendingReferralCode', referralCode);

      // Redirect to home
      setLocation('/');
      return;
    }

    // Check for referral code in query parameter (?ref=CODE)
    const searchParams = new URLSearchParams(window.location.search);
    const refParam = searchParams.get('ref');

    if (refParam) {
      console.log('🎁 Referral code captured from query param:', refParam);

      // Store in localStorage
      localStorage.setItem('pendingReferralCode', refParam);

      // Don't redirect, just store it - user is already in Mini App
    }
  }, [setLocation]);

  return null;
}

function Router() {
  return (
    <>
      <Navigation />
      <DeepLinkHandler />
      <ReferralHandler />
      <Switch>
        <Route path="/" component={Explore} />
        <Route path="/explore" component={Explore} />
        <Route path="/r/:code">
          {() => <div className="min-h-screen flex items-center justify-center">
            <p className="text-white">Loading referral...</p>
          </div>}
        </Route>
        <Route path="/marketplace" component={Marketplace} />
        <Route path="/my-nfts" component={MyNFTs} />
        <Route path="/mint" component={Mint} />
        <Route path="/quests" component={Quests} />
        <Route path="/leaderboard" component={Leaderboard} />
        <Route path="/badges" component={Badges} />
        <Route path="/travel-ai" component={TravelAI} />
        <Route path="/faq">{() => <Faq />}</Route>
        <Route path="/about" component={About} />
        <Route path="/contact" component={Contact} />
        <Route path="/privacy" component={Privacy} />
        <Route path="/admin/notifications" component={AdminNotifications} />
        <Route path="/nft/:tokenId" component={NFTDetail} />
        <Route>
          <div className="min-h-screen flex items-center justify-center">
            <div className="text-center">
              <h1 className="text-2xl font-bold mb-4">Page Not Found</h1>
              <p className="text-muted-foreground">The page you're looking for doesn't exist.</p>
            </div>
          </div>
        </Route>
      </Switch>
    </>
  );
}

function App() {
  const [context, setContext] = useState<any>(null);
  const [isError, setIsError] = useState(false);

  useEffect(() => {
    console.log('🎯 TravelMint App starting...');

    try {
      // Get Farcaster context if available (optional, non-blocking, safe)
      if (typeof window !== 'undefined' && sdk?.context) {
        // Wrap in setTimeout to prevent blocking app initialization
        setTimeout(async () => {
          try {
            let appContext;
            try {
              appContext = await Promise.resolve(sdk.context);
            } catch (contextError) {
              // Fallback: try treating it as a direct object
              appContext = sdk.context as any;
            }

            if (appContext) {
              setContext(appContext);
              console.log('✅ Farcaster context loaded:', appContext?.user?.displayName || 'User');
            }
          } catch (error) {
            // Silent fail - don't let Farcaster context issues crash app
            console.log('ℹ️ Running in web browser mode (Farcaster context not available):', (error as any)?.message || error);
          }
        }, 100); // Small delay to prevent blocking
      } else {
        console.log('🌐 No Farcaster SDK available - running in standard web browser');
      }
    } catch (error) {
      console.error('🚨 CRITICAL: App initialization failed:', error);
      setIsError(true);
    }
  }, []);

  // Emergency fallback for Farcaster iframe issues
  if (isError) {
    return (
      <div style={{ 
        minHeight: '100vh', 
        display: 'flex', 
        alignItems: 'center', 
        justifyContent: 'center',
        backgroundColor: '#0f172a',
        color: 'white',
        fontFamily: 'system-ui, sans-serif'
      }}>
        <div style={{ textAlign: 'center', padding: '2rem' }}>
          <h1 style={{ fontSize: '1.5rem', fontWeight: 'bold', marginBottom: '1rem' }}>
            TravelMint Initialization Error
          </h1>
          <p style={{ marginBottom: '1rem', opacity: 0.8 }}>
            Failed to start in current environment
          </p>
          <button 
            onClick={() => window.location.reload()}
            style={{
              backgroundColor: '#3b82f6',
              color: 'white',
              padding: '0.5rem 1rem',
              borderRadius: '0.375rem',
              border: 'none',
              cursor: 'pointer'
            }}
          >
            Retry
          </button>
        </div>
      </div>
    );
  }

  return (
    <QueryClientProvider client={queryClient}>
      <FarcasterAuthProvider>
        <WalletProvider>
          <ErrorBoundary>
            <TooltipProvider>
              <Toaster />
              <Router />
            </TooltipProvider>
          </ErrorBoundary>
        </WalletProvider>
      </FarcasterAuthProvider>
    </QueryClientProvider>
  );
}

export default App;

