      const lat = parseFloat(nft.latitude || '0');
      const lng = parseFloat(nft.longitude || '0');
      const hasValidCoordinates = !(lat === 0 && lng === 0);

      return hasValidCoordinates;
    })
    .sort((a, b) => {
