import { useState, useEffect } from "react";
import { useRoute, useLocation } from "wouter";
import { useQuery } from "@tanstack/react-query";
import { useAccount, useSendCalls } from "wagmi";
import { parseUnits, encodeFunctionData } from "viem";
import { Button } from "@/components/ui/button";
import { useToast } from "@/hooks/use-toast";
import { ArrowLeft, MapPin, User, Clock, Loader2, Heart } from "lucide-react";
import { useFarcasterAuth } from "@/hooks/use-farcaster-auth";

interface NFT {
  id: string;
  tokenId?: string;
  title: string;
  description?: string;
  imageUrl: string;
  objectStorageUrl?: string;
  location: string;
  latitude?: string;
  longitude?: string;
  price: string;
  category?: string;
  isForSale: number;
  createdAt: string;
  ownerAddress: string;
  creatorAddress: string;
  farcasterOwnerUsername?: string | null;
  farcasterOwnerFid?: string | null;
  farcasterCreatorUsername?: string | null;
  farcasterCreatorFid?: string | null;
  likeCount?: number;
  isLiked?: boolean;
  creator?: { username: string; avatar?: string } | null;
  owner?: { username: string; avatar?: string } | null;
}

const MODAL_PLACEHOLDER = `data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" width="400" height="320" viewBox="0 0 400 320"><rect width="100%" height="100%" fill="%23f8fafc"/><rect x="30" y="30" width="340" height="260" rx="12" fill="%23e2e8f0" stroke="%23cbd5e1" stroke-width="3"/><circle cx="200" cy="160" r="30" fill="%23fbbf24"/><text x="200" y="290" text-anchor="middle" fill="%23475569" font-size="14" font-family="Inter,sans-serif">📷 Loading...</text></svg>`;

const USDC_ADDRESS = "0x833589fCD6eDb6E08f4c7C32D4f71b54bdA02913" as `0x${string}`;
const TREASURY_ADDRESS = "0x7CDe7822456AAC667Df0420cD048295b92704084" as `0x${string}`;

const USDC_ABI = [
  {
    name: "transfer",
    type: "function",
    stateMutability: "nonpayable",
    inputs: [
      { name: "to", type: "address" },
      { name: "amount", type: "uint256" }
    ],
    outputs: [{ name: "", type: "bool" }]
  }
] as const;

export default function NFTDetail() {
  const [, params] = useRoute("/nft/:tokenId");
  const [, setLocation] = useLocation();
  const tokenId = params?.tokenId;
  const { toast } = useToast();
  const { address: walletAddress, isConnected } = useAccount();
  const { user: farcasterUser } = useFarcasterAuth();

  const [donationAmount, setDonationAmount] = useState<number | null>(null);
  const [isDonating, setIsDonating] = useState(false);
  const [imageSrc, setImageSrc] = useState(MODAL_PLACEHOLDER);
  const [imageLoading, setImageLoading] = useState(true);
  const [customTipAmount, setCustomTipAmount] = useState<string>("");
  const [donationRecorded, setDonationRecorded] = useState(false);

  const { data: donationCallsData, sendCalls: sendDonationCalls, isPending: isDonationPending } = useSendCalls();

  const { data: nft, isLoading, error } = useQuery<NFT>({
    queryKey: ['/api/nft/token', tokenId],
    enabled: !!tokenId,
  });

  useEffect(() => {
    if (!nft) return;

    const url = nft.objectStorageUrl || nft.imageUrl;
    if (!url) return;

    const img = new Image();
    img.onload = () => {
      setImageSrc(url);
      setImageLoading(false);
    };
    img.onerror = () => {
      setImageSrc(nft.imageUrl);
      setImageLoading(false);
    };
    img.src = url;
  }, [nft]);

  // Record donation to database when blockchain transaction completes
  useEffect(() => {
    if (!donationCallsData || !isDonating || !nft || !donationAmount || !walletAddress || donationRecorded) return;

    console.log('🎉 Donation batch transaction completed!', donationCallsData);
    setDonationRecorded(true);

    const recordDonation = async () => {
      try {
        const platformFee = donationAmount * 0.1;
        const creatorAmount = donationAmount * 0.9;

        await fetch('/api/donations', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            nftId: nft.id,
            fromAddress: walletAddress,
            toAddress: nft.creatorAddress,
            amount: creatorAmount.toString(),
            platformFee: platformFee.toString(),
            blockchainTxHash: typeof donationCallsData === 'string' ? donationCallsData : (donationCallsData as any).id || `donation-${Date.now()}`,
          }),
        });
        console.log('💝 Donation recorded in database');
      } catch (error) {
        console.error('Failed to record donation:', error);
      }
    };

    recordDonation();

    const creatorName = nft.farcasterCreatorUsername || 
                       nft.creator?.username || 
                       `${nft.creatorAddress.slice(0, 6)}...${nft.creatorAddress.slice(-4)}`;

    toast({
      title: "Donation Sent!",
      description: `Thank you for supporting @${creatorName}!`,
    });

    setIsDonating(false);
    setDonationAmount(null);
    setCustomTipAmount("");
  }, [donationCallsData, isDonating, nft, donationAmount, walletAddress, donationRecorded, toast]);

  const handleCustomTip = () => {
    const amount = parseFloat(customTipAmount);
    if (isNaN(amount) || amount < 1) {
      toast({
        title: "Invalid Amount",
        description: "Minimum tip amount is 1 USDC",
        variant: "destructive",
      });
      return;
    }
    handleDonation(amount);
  };

  const handleDonation = async (amount: number) => {
    if (!isConnected || !walletAddress) {
      toast({
        title: "Wallet Not Connected",
        description: "Please connect your wallet to donate",
        variant: "destructive",
      });
      return;
    }

    if (!nft) {
      toast({
        title: "Error",
        description: "NFT not found",
        variant: "destructive",
      });
      return;
    }

    if (nft.creatorAddress.toLowerCase() === walletAddress.toLowerCase()) {
      toast({
        title: "Cannot Donate to Yourself",
        description: "You cannot donate to your own NFT",
        variant: "destructive",
      });
      return;
    }

    setDonationAmount(amount);
    setIsDonating(true);
    setDonationRecorded(false); // Reset for new donation

    try {
      const donationWei = parseUnits(amount.toString(), 6);
      const creatorAmount = (donationWei * BigInt(90)) / BigInt(100);
      const treasuryAmount = (donationWei * BigInt(10)) / BigInt(100);

      const creatorAmountDecimal = Number(creatorAmount) / 1e6;
      const platformFeeDecimal = Number(treasuryAmount) / 1e6;

      toast({
        title: "Processing Donation",
        description: `Donating ${amount} USDC (${creatorAmountDecimal.toFixed(2)} to creator, ${platformFeeDecimal.toFixed(2)} platform fee)`,
      });

      const batchCalls = [
        {
          to: USDC_ADDRESS,
          data: encodeFunctionData({
            abi: USDC_ABI,
            functionName: "transfer",
            args: [nft.creatorAddress as `0x${string}`, creatorAmount],
          }),
        },
        {
          to: USDC_ADDRESS,
          data: encodeFunctionData({
            abi: USDC_ABI,
            functionName: "transfer",
            args: [TREASURY_ADDRESS, treasuryAmount],
          }),
        },
      ];

      // Send blockchain transaction - useEffect will handle recording to database
      await sendDonationCalls({
        calls: batchCalls,
      });

    } catch (error: any) {
      console.error("Donation error:", error);
      setIsDonating(false);
      setDonationAmount(null);
      toast({
        title: "Donation Failed",
        description: error?.message || "Transaction was cancelled or failed",
        variant: "destructive",
      });
    }
  };

  const formatDate = (dateString: string) => {
    try {
      return new Intl.DateTimeFormat('en-US', {
        year: 'numeric',
        month: 'short',
        day: 'numeric',
      }).format(new Date(dateString));
    } catch {
      return 'Unknown date';
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <div className="text-center">
          <Loader2 className="w-8 h-8 animate-spin mx-auto mb-4 text-primary" />
          <p className="text-muted-foreground">Loading NFT...</p>
        </div>
      </div>
    );
  }

  if (error || !nft) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <div className="text-center">
          <h1 className="text-2xl font-bold mb-4">NFT Not Found</h1>
          <p className="text-muted-foreground mb-6">
            The NFT you're looking for could not be found.
          </p>
          <Button onClick={() => setLocation("/explore")} data-testid="button-back-explore">
            <ArrowLeft className="w-4 h-4 mr-2" />
            Back to Explore
          </Button>
        </div>
      </div>
    );
  }

  const creatorName = nft.farcasterCreatorUsername || nft.creator?.username || 
    (nft.creatorAddress ? `${nft.creatorAddress.slice(0, 6)}...${nft.creatorAddress.slice(-4)}` : 'Unknown');
  const ownerName = nft.farcasterOwnerUsername || nft.owner?.username ||
    (nft.ownerAddress ? `${nft.ownerAddress.slice(0, 6)}...${nft.ownerAddress.slice(-4)}` : 'Unknown');

  return (
    <div className="min-h-screen bg-background">
      <div className="container mx-auto px-4 py-6 max-w-4xl">
        <Button 
          variant="ghost" 
          onClick={() => setLocation("/explore")}
          className="mb-4"
          data-testid="button-back-explore"
        >
          <ArrowLeft className="w-4 h-4 mr-2" />
          Back to Explore
        </Button>

        <div className="bg-card rounded-2xl overflow-hidden shadow-xl border">
          <div className="relative">
            <img
              src={imageSrc}
              alt={nft.title}
              className="w-full aspect-video object-cover"
              data-testid="img-nft-detail"
            />
            <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-black/80 to-transparent p-6">
              <h1 className="text-2xl md:text-3xl font-bold text-white mb-2" data-testid="text-nft-title">
                {nft.title}
              </h1>
              <div className="flex items-center text-white/80">
                <MapPin className="w-4 h-4 mr-2" />
                <span data-testid="text-nft-location">{nft.location}</span>
              </div>
            </div>

            {nft.likeCount !== undefined && (
              <div className="absolute bottom-3 right-3 flex items-center gap-1.5 bg-black/60 text-white px-3 py-2 rounded-full">
                <Heart className={`w-5 h-5 ${nft.isLiked ? 'fill-red-500 text-red-500' : ''}`} />
                <span className="text-sm font-medium">{nft.likeCount || 0}</span>
              </div>
            )}
          </div>

          <div className="p-6 space-y-6">
            {(!walletAddress || walletAddress.toLowerCase() !== nft.creatorAddress?.toLowerCase()) && (
              <div className="bg-gradient-to-r from-primary/10 to-accent/10 p-6 rounded-xl border border-primary/20">
                <h3 className="text-xl font-bold mb-2">💰 Support the Creator</h3>
                <p className="text-muted-foreground mb-4">
                  Donate USDC to @{nft.farcasterCreatorUsername || creatorName}
                </p>
                <div className="grid grid-cols-3 gap-3 mb-3">
                  {[0.1, 0.5, 1].map((amount) => (
                    <Button
                      key={amount}
                      onClick={() => handleDonation(amount)}
                      disabled={isDonating || isDonationPending || !isConnected}
                      variant={donationAmount === amount ? "default" : "outline"}
                      className="w-full text-lg py-6"
                      data-testid={`donation-button-${amount}`}
                    >
                      {(isDonating || isDonationPending) && donationAmount === amount ? (
                        <span className="flex items-center gap-2">
                          <Loader2 className="w-4 h-4 animate-spin" />
                          {amount}
                        </span>
                      ) : (
                        `${amount} USDC`
                      )}
                    </Button>
                  ))}
                </div>
                <div className="flex gap-2">
                  <input
                    type="number"
                    min="1"
                    step="0.1"
                    placeholder="Custom amount (min 1 USDC)"
                    value={customTipAmount}
                    onChange={(e) => setCustomTipAmount(e.target.value)}
                    disabled={isDonating || isDonationPending || !isConnected}
                    className="flex-1 px-4 py-3 rounded-lg border bg-background text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary"
                    data-testid="input-custom-tip"
                  />
                  <Button
                    onClick={handleCustomTip}
                    disabled={isDonating || isDonationPending || !isConnected || !customTipAmount}
                    className="px-6 py-3"
                    data-testid="button-custom-tip"
                  >
                    {(isDonating || isDonationPending) && donationAmount === parseFloat(customTipAmount) ? (
                      <Loader2 className="w-4 h-4 animate-spin" />
                    ) : (
                      "Tip"
                    )}
                  </Button>
                </div>
                {!isConnected && (
                  <p className="text-sm text-muted-foreground mt-3 text-center">
                    Connect your wallet to donate
                  </p>
                )}
              </div>
            )}

            {nft.description && (
              <div>
                <h3 className="font-semibold mb-2">Description</h3>
                <p className="text-muted-foreground" data-testid="text-nft-description">
                  {nft.description}
                </p>
              </div>
            )}

            <div className="grid md:grid-cols-2 gap-6">
              <div>
                <h3 className="font-semibold mb-2">Creator</h3>
                <div className="flex items-center space-x-2">
                  {nft.creator?.avatar ? (
                    <img
                      src={nft.creator.avatar}
                      alt="Creator"
                      className="w-8 h-8 rounded-full"
                    />
                  ) : (
                    <div className="w-8 h-8 bg-muted rounded-full flex items-center justify-center">
                      <User className="w-4 h-4" />
                    </div>
                  )}
                  <span className="text-sm" data-testid="text-creator-name">
                    @{creatorName}
                  </span>
                </div>
              </div>

              <div>
                <h3 className="font-semibold mb-2">Owner</h3>
                <div className="flex items-center space-x-2">
                  {nft.owner?.avatar ? (
                    <img
                      src={nft.owner.avatar}
                      alt="Owner"
                      className="w-8 h-8 rounded-full"
                    />
                  ) : (
                    <div className="w-8 h-8 bg-muted rounded-full flex items-center justify-center">
                      <User className="w-4 h-4" />
                    </div>
                  )}
                  <span className="text-sm" data-testid="text-owner-name">
                    @{ownerName}
                  </span>
                </div>
              </div>
            </div>

            {nft.isForSale === 1 && (
              <div className="flex items-center justify-between p-4 bg-muted rounded-lg">
                <div>
                  <p className="text-sm text-muted-foreground">Price</p>
                  <p className="text-2xl font-bold" data-testid="text-nft-price">
                    {parseFloat(nft.price).toFixed(0)} USDC
                  </p>
                </div>
                <Button 
                  className="bg-primary hover:bg-primary/90 text-primary-foreground"
                  onClick={() => setLocation('/marketplace')}
                  data-testid="button-view-marketplace"
                >
                  View in Marketplace
                </Button>
              </div>
            )}

            <div>
              <h3 className="font-semibold mb-2">Created</h3>
              <div className="flex items-center text-muted-foreground">
                <Clock className="w-4 h-4 mr-2" />
                <span data-testid="text-nft-created">{formatDate(nft.createdAt)}</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

server/image-sync.ts.content:
import { storage } from "./storage";
import { ObjectStorageService } from "./objectStorage";
import type { NFT } from "@shared/schema";

const objectStorageService = new ObjectStorageService();

const IPFS_GATEWAYS = [
  "https://ipfs.io/ipfs/",
  "https://cloudflare-ipfs.com/ipfs/",
  "https://dweb.link/ipfs/",
  "https://4everland.io/ipfs/",
  "https://gateway.pinata.cloud/ipfs/"
];

const MAX_FILE_SIZE = 10 * 1024 * 1024;
const DOWNLOAD_TIMEOUT = 30000;
const DELAY_BETWEEN_DOWNLOADS = 500;

function extractIpfsCid(url: string): string | null {
  if (!url) return null;

  // Handle ipfs:// protocol (e.g., ipfs://QmXxx or ipfs://ipfs/QmXxx)
  if (url.startsWith('ipfs://')) {
    let path = url.slice(7); // Remove 'ipfs://'
    // Handle ipfs://ipfs/QmXxx format
    if (path.startsWith('ipfs/')) {
      path = path.slice(5);
    }
    // Extract just the CID (remove query params and paths)
    const cid = path.split('?')[0].split('/')[0];
    return cid.length > 10 ? cid : null;
  }

  // Handle subdomain-style gateways (e.g., https://<cid>.ipfs.dweb.link/)
  const subdomainMatch = url.match(/https?:\/\/([a-zA-Z0-9]+)\.ipfs\./);
  if (subdomainMatch) {
    return subdomainMatch[1];
  }

  // Handle path-style gateways (e.g., https://gateway.com/ipfs/<cid>)
  const ipfsMatch = url.match(/\/ipfs\/([a-zA-Z0-9]+)/);
  if (ipfsMatch) {
    return ipfsMatch[1];
  }

  return null;
}

function getFileExtension(contentType: string): string {
  const mimeToExt: Record<string, string> = {
    'image/jpeg': 'jpg',
    'image/jpg': 'jpg',
    'image/png': 'png',
    'image/gif': 'gif',
    'image/webp': 'webp',
    'image/svg+xml': 'svg',
    'image/avif': 'avif'
  };
  return mimeToExt[contentType] || 'jpg';
}

async function downloadImageWithTimeout(url: string, timeout: number): Promise<{ buffer: Buffer; contentType: string } | null> {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), timeout);

  try {
    const response = await fetch(url, { 
      signal: controller.signal,
      headers: {
        'User-Agent': 'TravelMint-NFT-Sync/1.0'
      }
    });

    if (!response.ok) {
      return null;
    }

    const contentType = response.headers.get('content-type') || 'image/jpeg';
    const contentLength = response.headers.get('content-length');

    if (contentLength && parseInt(contentLength) > MAX_FILE_SIZE) {
      console.log(`⚠️ Image too large: ${parseInt(contentLength) / 1024 / 1024}MB`);
      return null;
    }

    const arrayBuffer = await response.arrayBuffer();
    const buffer = Buffer.from(arrayBuffer);

    if (buffer.length > MAX_FILE_SIZE) {
      console.log(`⚠️ Downloaded image too large: ${buffer.length / 1024 / 1024}MB`);
      return null;
    }

    return { buffer, contentType };
  } catch (error: any) {
    if (error.name === 'AbortError') {
      return null;
    }
    return null;
  } finally {
    clearTimeout(timeoutId);
  }
}

async function downloadFromIpfs(cid: string): Promise<{ buffer: Buffer; contentType: string } | null> {
  for (let i = 0; i < IPFS_GATEWAYS.length; i++) {
    const gateway = IPFS_GATEWAYS[i];
    const url = `${gateway}${cid}`;

    console.log(`🔗 Trying gateway ${i + 1}/${IPFS_GATEWAYS.length}: ${gateway}`);

    const result = await downloadImageWithTimeout(url, DOWNLOAD_TIMEOUT);
    if (result) {
      console.log(`✅ Successfully downloaded from ${gateway}`);
      return result;
    }
  }

  return null;
}

async function syncNftImage(nft: NFT, force: boolean = false): Promise<boolean> {
  try {
    // Skip if already cached (unless force=true)
    if (nft.objectStorageUrl && !force) {
      console.log(`⏭️ NFT ${nft.tokenId || nft.id} already cached, skipping`);
      return true;
    }

    const imageUrl = nft.imageUrl;
    if (!imageUrl) {
      console.log(`⚠️ NFT ${nft.id} has no imageUrl`);
      return false;
    }

    const cid = extractIpfsCid(imageUrl);

    let imageData: { buffer: Buffer; contentType: string } | null = null;

    if (cid) {
      console.log(`📥 Downloading IPFS image for NFT ${nft.tokenId || nft.id}: ${cid}`);
      imageData = await downloadFromIpfs(cid);
    } else if (imageUrl.startsWith('http')) {
      console.log(`📥 Downloading HTTP image for NFT ${nft.tokenId || nft.id}: ${imageUrl}`);
      imageData = await downloadImageWithTimeout(imageUrl, DOWNLOAD_TIMEOUT);
    }

    if (!imageData) {
      console.log(`❌ Failed to download image for NFT ${nft.tokenId || nft.id}`);
      return false;
    }

    const extension = getFileExtension(imageData.contentType);
    const fileName = `nft-${nft.tokenId || nft.id}.${extension}`;

    console.log(`📤 Uploading to Object Storage: ${fileName} (${(imageData.buffer.length / 1024).toFixed(1)}KB)`);

    const objectStorageUrl = await objectStorageService.uploadFileBuffer(
      imageData.buffer,
      fileName,
      imageData.contentType
    );

    await storage.updateNFT(nft.id, { objectStorageUrl });

    console.log(`✅ NFT ${nft.tokenId || nft.id} synced: ${objectStorageUrl}`);
    return true;
  } catch (error: any) {
    console.error(`❌ Error syncing NFT ${nft.id}:`, error.message);
    return false;
  }
}

export async function syncAllImages(): Promise<{ synced: number; failed: number; skipped: number }> {
  console.log('🔄 Starting NFT image sync...');

  const allNfts = await storage.getAllNFTs();

  // Get tip totals to prioritize tipped NFTs
  const tipTotals = await storage.getNFTTipTotals();

  const nftsToSync = allNfts.filter(nft => {
    if (nft.objectStorageUrl) {
      return false;
    }
    if (!nft.imageUrl) {
      return false;
    }
    return true;
  });

  // Prioritize tipped NFTs first (they appear in "Most Tips" filter)
  nftsToSync.sort((a, b) => {
    const tipsA = tipTotals.get(a.id) || 0;
    const tipsB = tipTotals.get(b.id) || 0;
    return tipsB - tipsA; // Higher tips first
  });

  const tippedCount = nftsToSync.filter(nft => (tipTotals.get(nft.id) || 0) > 0).length;
  console.log(`📊 Found ${nftsToSync.length} NFTs to sync (${tippedCount} with tips prioritized, ${allNfts.length} total)`);

  let synced = 0;
  let failed = 0;
  let skipped = allNfts.length - nftsToSync.length;

  for (let i = 0; i < nftsToSync.length; i++) {
    const nft = nftsToSync[i];
    console.log(`\n[${i + 1}/${nftsToSync.length}] Processing NFT: ${nft.title || nft.tokenId || nft.id}`);

    const success = await syncNftImage(nft);
    if (success) {
      synced++;
    } else {
      failed++;
    }

    if (i < nftsToSync.length - 1) {
      await new Promise(resolve => setTimeout(resolve, DELAY_BETWEEN_DOWNLOADS));
    }
  }

  console.log(`\n✅ Sync complete: ${synced} synced, ${failed} failed, ${skipped} already cached`);

  return { synced, failed, skipped };
}

export async function syncSingleImage(nftId: string): Promise<boolean> {
  const nft = await storage.getNFT(nftId);
  if (!nft) {
    console.log(`❌ NFT not found: ${nftId}`);
    return false;
  }

  return syncNftImage(nft);
}

export async function getSyncStatus(): Promise<{
  total: number;
  cached: number;
  pending: number;
  percentage: number;
}> {
  const allNfts = await storage.getAllNFTs();
  const cached = allNfts.filter(nft => nft.objectStorageUrl).length;
  const pending = allNfts.length - cached;
  const percentage = allNfts.length > 0 ? Math.round((cached / allNfts.length) * 100) : 0;

  return { total: allNfts.length, cached, pending, percentage };
}

