    category,
    label: CATEGORY_LABELS[category],
    badges: BADGE_DEFINITIONS.filter(b => b.category === category),
  }));

  const isSelectedEarned = selectedBadge ? earnedBadgeCodes.has(selectedBadge.code) : false;

