                  </div>
                )}
              </div>

              <span className={`mt-2 text-xs text-center font-medium ${hasEarlyBird ? "text-white" : "text-gray-500"}`}>
                EarlyBird
              </span>
            </div>
          </div>
        </div>

        <div className="text-center text-gray-500 text-sm mt-8">
          <p>
            {earnedBadgeCodes.size + (hasEarlyBird ? 1 : 0)} / {BADGE_DEFINITIONS.length + 1} badges earned
          </p>
        </div>
      </div>

      {/* EarlyBird Dialog */}
      <Dialog open={showEarlyBirdDialog} onOpenChange={setShowEarlyBirdDialog}>
        <DialogContent className="bg-gray-900 border-gray-800 text-white max-w-sm">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              {hasEarlyBird ? (
                <CheckCircle className="w-5 h-5 text-green-500" />
              ) : (
                <Lock className="w-5 h-5 text-gray-500" />
              )}
              EarlyBird Badge
            </DialogTitle>
          </DialogHeader>

          <div className="flex flex-col items-center gap-4 py-4">
            <div className="relative">
              <div 
                className={`w-32 h-32 rounded-3xl flex items-center justify-center shadow-xl overflow-hidden ${
                  hasEarlyBird 
                    ? "" 
                    : "bg-gray-700 opacity-40"
                }`}
              >
                {earlyBirdImage ? (
                  <img 
                    src={earlyBirdImage} 
                    alt="EarlyBird NFT" 
                    className={`w-full h-full object-cover ${hasEarlyBird ? "" : "grayscale"}`}
                  />
                ) : (
                  <div className={`w-full h-full flex items-center justify-center ${hasEarlyBird ? "bg-gradient-to-br from-yellow-400 to-orange-500" : ""}`}>
                    <Bird className={`w-16 h-16 ${hasEarlyBird ? "text-white" : "text-gray-400"}`} />
                  </div>
                )}
              </div>
              {hasEarlyBird && (
                <div className="absolute -top-2 -right-2 bg-green-500 text-white text-xs px-2 py-1 rounded-full font-semibold">
                  Earned!
                </div>
              )}
            </div>

            <div className="text-center">
              <p className="text-gray-300 mb-2">Exclusive badge for early TravelMint supporters</p>
              <p className="text-xs text-gray-500">
                Category: Special Badges
              </p>
            </div>

            {!hasEarlyBird && (
              <div className="bg-gray-800 rounded-lg px-4 py-2 text-center">
                <p className="text-sm text-gray-400">
                  This badge was given to early supporters only
                </p>
              </div>
            )}
          </div>
        </DialogContent>
      </Dialog>

      <Dialog open={!!selectedBadge} onOpenChange={(open) => !open && setSelectedBadge(null)}>
        <DialogContent className="bg-gray-900 border-gray-800 text-white max-w-sm">
          {selectedBadge && (
            <>
              <DialogHeader>
                <DialogTitle className="flex items-center gap-2">
                  {isSelectedEarned ? (
                    <CheckCircle className="w-5 h-5 text-green-500" />
                  ) : (
                    <Lock className="w-5 h-5 text-gray-500" />
                  )}
                  {selectedBadge.name}
                </DialogTitle>
              </DialogHeader>

              <div className="flex flex-col items-center gap-4 py-4">
                <div className="relative">
                  <div 
                    className={`w-32 h-32 rounded-3xl flex items-center justify-center shadow-xl ${
                      isSelectedEarned 
                        ? selectedBadge.bgColor 
                        : "bg-gray-700"
                    } ${isSelectedEarned ? "" : "opacity-40"}`}
                  >
                    <selectedBadge.icon className={`w-16 h-16 ${isSelectedEarned ? selectedBadge.iconColor : "text-gray-400"}`} />
                  </div>
                  {isSelectedEarned && (
                    <div className="absolute -top-2 -right-2 bg-green-500 text-white text-xs px-2 py-1 rounded-full font-semibold">
                      Earned!
                    </div>
                  )}
                </div>

                <div className="text-center">
                  <p className="text-gray-300 mb-2">{selectedBadge.description}</p>
                  <p className="text-xs text-gray-500">
                    Category: {CATEGORY_LABELS[selectedBadge.category]}
                  </p>
                </div>

                {!isSelectedEarned && (
                  <div className="bg-gray-800 rounded-lg px-4 py-2 text-center">
                    <p className="text-sm text-gray-400">
                      Keep going to unlock this badge!
                    </p>
                  </div>
                )}
              </div>
            </>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

