import OpenAI from "openai";
import pRetry, { AbortError } from "p-retry";

// This is using Replit's AI Integrations service, which provides OpenRouter-compatible API access without requiring your own OpenRouter API key.
const openrouter = new OpenAI({
  baseURL: process.env.AI_INTEGRATIONS_OPENROUTER_BASE_URL,
  apiKey: process.env.AI_INTEGRATIONS_OPENROUTER_API_KEY
});

function isRateLimitError(error: any): boolean {
  const errorMsg = error?.message || String(error);
  return (
    errorMsg.includes("429") ||
    errorMsg.includes("RATELIMIT_EXCEEDED") ||
    errorMsg.toLowerCase().includes("quota") ||
    errorMsg.toLowerCase().includes("rate limit")
  );
}

export interface ChatMessage {
  role: "user" | "assistant";
  content: string;
}

export async function getTravelRecommendation(
  query: string,
  chatHistory: ChatMessage[] = []
): Promise<string> {
  const systemPrompt = `You are a helpful travel assistant. Provide concise, practical travel advice and recommendations.
IMPORTANT: Always respond in the SAME LANGUAGE as the user's message. If they write in Turkish, respond in Turkish. If they write in English, respond in English.
When recommending places, use **bold** formatting for place names (e.g., **Hagia Sophia**, **Blue Mosque**).
Focus only on what the user asks - don't add extra categories unless requested.
Keep responses informative but concise (2-3 sentences per recommendation).
If user asks about a specific topic (like cafes, museums, etc.), only provide info about that topic.
Use the conversation history to maintain context - if user mentioned a city before, remember it.`;

  const messages: any[] = [
    { role: "system", content: systemPrompt }
  ];

  // Add chat history for context (last 8 messages)
  const recentHistory = chatHistory.slice(-8);
  for (const msg of recentHistory) {
    messages.push({
      role: msg.role,
      content: msg.content
    });
  }

  // Add current query
  messages.push({ role: "user", content: query });

  try {
    const response = await pRetry(
      async () => {
        try {
          const completion = await openrouter.chat.completions.create({
            model: "meta-llama/llama-3.1-8b-instruct",
            messages: messages,
            max_tokens: 1024,
            temperature: 0.7,
          });
          return completion.choices[0]?.message?.content || "I couldn't generate a response. Please try again.";
        } catch (error: any) {
          if (isRateLimitError(error)) {
            throw error;
          }
          throw new AbortError(error);
        }
      },
      {
        retries: 3,
        minTimeout: 1000,
        maxTimeout: 8000,
        factor: 2,
      }
    );

    return response;
  } catch (error: any) {
    console.error("OpenRouter API error:", error);
    if (isRateLimitError(error)) {
      throw new Error("AI service is temporarily busy. Please try again in a few moments.");
    }
    throw new Error("Failed to get travel recommendation. Please try again.");
  }
}

server/overpass-service.ts.content:
// Overpass API Service for querying OpenStreetMap POI data
// Completely free, no API key required

interface OverpassPOI {
  id: number;
  type: 'node' | 'way' | 'relation';
  lat: number;
  lon: number;
  tags: {
    name?: string;
    amenity?: string;
    tourism?: string;
    shop?: string;
    leisure?: string;
    historic?: string;
    'addr:street'?: string;
    'addr:city'?: string;
    opening_hours?: string;
    website?: string;
    phone?: string;
    cuisine?: string;
    [key: string]: string | undefined;
  };
}

export interface POIResult {
  osmId: string;
  name: string;
  category: string;
  subcategory: string;
  lat: number;
  lon: number;
  address?: string;
  openingHours?: string;
  website?: string;
  phone?: string;
  cuisine?: string;
}

const OVERPASS_API_URL = 'https://overpass-api.de/api/interpreter';

// Category mapping for user-friendly display
function getCategory(tags: OverpassPOI['tags']): { category: string; subcategory: string } {
  if (tags.amenity) {
    const amenityMap: Record<string, string> = {
      'cafe': 'Kafe',
      'restaurant': 'Restoran',
      'bar': 'Bar',
      'pub': 'Pub',
      'fast_food': 'Fast Food',
      'museum': 'Müze',
      'theatre': 'Tiyatro',
      'cinema': 'Sinema',
      'library': 'Kütüphane',
      'place_of_worship': 'İbadet Yeri',
      'hospital': 'Hastane',
      'pharmacy': 'Eczane',
      'bank': 'Banka',
      'atm': 'ATM',
      'fuel': 'Benzin İstasyonu',
      'parking': 'Otopark',
    };
    return { 
      category: 'Mekan', 
      subcategory: amenityMap[tags.amenity] || tags.amenity 
    };
  }

  if (tags.tourism) {
    const tourismMap: Record<string, string> = {
      'attraction': 'Turistik Yer',
      'museum': 'Müze',
      'gallery': 'Galeri',
      'viewpoint': 'Manzara Noktası',
      'hotel': 'Otel',
      'hostel': 'Hostel',
      'guest_house': 'Pansiyon',
      'monument': 'Anıt',
      'artwork': 'Sanat Eseri',
    };
    return { 
      category: 'Turizm', 
      subcategory: tourismMap[tags.tourism] || tags.tourism 
    };
  }

  if (tags.shop) {
    const shopMap: Record<string, string> = {
      'supermarket': 'Süpermarket',
      'convenience': 'Market',
      'clothes': 'Giyim',
      'electronics': 'Elektronik',
      'books': 'Kitapçı',
      'bakery': 'Fırın',
      'butcher': 'Kasap',
      'jewelry': 'Kuyumcu',
    };
    return { 
      category: 'Mağaza', 
      subcategory: shopMap[tags.shop] || tags.shop 
    };
  }

  if (tags.leisure) {
    const leisureMap: Record<string, string> = {
      'park': 'Park',
      'garden': 'Bahçe',
      'playground': 'Oyun Alanı',
      'sports_centre': 'Spor Merkezi',
      'stadium': 'Stadyum',
      'swimming_pool': 'Yüzme Havuzu',
    };
    return { 
      category: 'Eğlence', 
      subcategory: leisureMap[tags.leisure] || tags.leisure 
    };
  }

  if (tags.historic) {
    return { 
      category: 'Tarihi', 
      subcategory: tags.historic 
    };
  }

  return { category: 'Diğer', subcategory: 'Mekan' };
}

// Query nearby POIs using Overpass API
export async function getNearbyPOIs(
  lat: number,
  lon: number,
  radiusMeters: number = 500,
  categories: string[] = ['amenity', 'tourism', 'shop', 'leisure', 'historic']
): Promise<POIResult[]> {
  // Build Overpass QL query for multiple categories
  const categoryFilters = categories.map(cat => `node["${cat}"](around:${radiusMeters},${lat},${lon});`).join('\n');

  const query = `
    [out:json][timeout:25];
    (
      ${categoryFilters}
    );
    out body;
  `;

  try {
    const response = await fetch(OVERPASS_API_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: `data=${encodeURIComponent(query)}`,
    });

    if (!response.ok) {
      throw new Error(`Overpass API error: ${response.status}`);
    }

    const data = await response.json();
    const elements: OverpassPOI[] = data.elements || [];

    // Transform to our POI format
    const pois: POIResult[] = elements
      .filter(el => el.tags?.name) // Only include named places
      .map(el => {
        const { category, subcategory } = getCategory(el.tags);
        return {
          osmId: `${el.type}/${el.id}`,
          name: el.tags.name!,
          category,
          subcategory,
          lat: el.lat,
          lon: el.lon,
          address: el.tags['addr:street'] 
            ? `${el.tags['addr:street']}${el.tags['addr:city'] ? ', ' + el.tags['addr:city'] : ''}`
            : undefined,
          openingHours: el.tags.opening_hours,
          website: el.tags.website,
          phone: el.tags.phone,
          cuisine: el.tags.cuisine,
        };
      });

    return pois;
  } catch (error) {
    console.error('Overpass API error:', error);
    throw new Error('Failed to fetch nearby places. Please try again.');
  }
}

// Search for POIs by name in a bounding box
export async function searchPOIs(
  searchQuery: string,
  south: number,
  west: number,
  north: number,
  east: number,
  limit: number = 50
): Promise<POIResult[]> {
  const query = `
    [out:json][timeout:25];
    (
      node["name"~"${searchQuery}",i](${south},${west},${north},${east});
    );
    out body ${limit};
  `;

  try {
    const response = await fetch(OVERPASS_API_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: `data=${encodeURIComponent(query)}`,
    });

    if (!response.ok) {
      throw new Error(`Overpass API error: ${response.status}`);
    }

    const data = await response.json();
    const elements: OverpassPOI[] = data.elements || [];

    const pois: POIResult[] = elements
      .filter(el => el.tags?.name)
      .map(el => {
        const { category, subcategory } = getCategory(el.tags);
        return {
          osmId: `${el.type}/${el.id}`,
          name: el.tags.name!,
          category,
          subcategory,
          lat: el.lat,
          lon: el.lon,
          address: el.tags['addr:street'] 
            ? `${el.tags['addr:street']}${el.tags['addr:city'] ? ', ' + el.tags['addr:city'] : ''}`
            : undefined,
          openingHours: el.tags.opening_hours,
          website: el.tags.website,
          phone: el.tags.phone,
          cuisine: el.tags.cuisine,
        };
      });

    return pois;
  } catch (error) {
    console.error('Overpass API search error:', error);
    throw new Error('Failed to search places. Please try again.');
  }
}

// Get POI details by OSM ID
export async function getPOIDetails(osmId: string): Promise<POIResult | null> {
  const [type, id] = osmId.split('/');

  const query = `
    [out:json][timeout:10];
    ${type}(${id});
    out body;
  `;

  try {
    const response = await fetch(OVERPASS_API_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: `data=${encodeURIComponent(query)}`,
    });

    if (!response.ok) {
      throw new Error(`Overpass API error: ${response.status}`);
    }

    const data = await response.json();
    const element = data.elements?.[0] as OverpassPOI | undefined;

    if (!element || !element.tags?.name) {
      return null;
    }

    const { category, subcategory } = getCategory(element.tags);
    return {
      osmId,
      name: element.tags.name,
      category,
      subcategory,
      lat: element.lat,
      lon: element.lon,
      address: element.tags['addr:street'] 
        ? `${element.tags['addr:street']}${element.tags['addr:city'] ? ', ' + element.tags['addr:city'] : ''}`
        : undefined,
      openingHours: element.tags.opening_hours,
      website: element.tags.website,
      phone: element.tags.phone,
      cuisine: element.tags.cuisine,
    };
  } catch (error) {
    console.error('Overpass API details error:', error);
    return null;
  }
}

server/wikipedia-service.ts.content:
// Wikipedia API Service - Free image and info fetching
// Uses Wikimedia Commons REST API (completely free, no API key needed)

interface WikipediaResult {
  title: string;
  imageUrl: string | null;
  thumbnailUrl: string | null;
  description: string | null;
  pageUrl: string | null;
}

export async function getWikipediaInfo(placeName: string, city?: string): Promise<WikipediaResult | null> {
  try {
    // Build search query with city context for better results
    const searchQuery = city ? `${placeName} ${city}` : placeName;

    // Use Wikipedia REST API to search for the place
    const searchUrl = `https://en.wikipedia.org/api/rest_v1/page/summary/${encodeURIComponent(searchQuery.replace(/ /g, '_'))}`;

    const response = await fetch(searchUrl, {
      headers: {
        'User-Agent': 'TravelMint/1.0 (travel app; contact@travelmint.app)'
      }
    });

    if (!response.ok) {
      // Try with just the place name if city-specific search fails
      if (city) {
        return getWikipediaInfo(placeName);
      }
      return null;
    }

    const data = await response.json();

    return {
      title: data.title || placeName,
      imageUrl: data.originalimage?.source || null,
      thumbnailUrl: data.thumbnail?.source || null,
      description: data.extract || null,
      pageUrl: data.content_urls?.desktop?.page || null
    };
  } catch (error) {
    console.error('Wikipedia API error:', error);
    return null;
  }
}

export async function getPlaceImages(placeNames: string[], city: string): Promise<Map<string, WikipediaResult>> {
  const results = new Map<string, WikipediaResult>();

  // Fetch images in parallel but limit concurrency
  const promises = placeNames.slice(0, 5).map(async (name) => {
    const result = await getWikipediaInfo(name, city);
    if (result) {
      results.set(name, result);
    }
  });

  await Promise.allSettled(promises);
  return results;
}

