import { useState, useEffect, useCallback } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { MapPin, Search, Coffee, Utensils, Camera, Building, Trees, History, Navigation, CheckCircle2, Loader2, MapPinned } from "lucide-react";
import { useAccount } from "wagmi";
import { useFarcasterAuth } from "@/hooks/use-farcaster-auth";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";

interface POI {
  osmId: string;
  name: string;
  category: string;
  subcategory: string;
  lat: number;
  lon: number;
  address?: string;
  openingHours?: string;
  website?: string;
  phone?: string;
  cuisine?: string;
}

interface Checkin {
  id: string;
  wallet_address: string;
  osm_id: string;
  place_name: string;
  place_category: string;
  place_subcategory?: string;
  latitude: string;
  longitude: string;
  points_earned: number;
  created_at: string;
}

interface CheckinStats {
  totalCheckins: number;
  uniquePlaces: number;
  totalPoints: number;
  categoryCounts: { place_category: string; count: string }[];
}

const categoryIcons: Record<string, typeof Coffee> = {
  'Mekan': Building,
  'Turizm': Camera,
  'Mağaza': Building,
  'Eğlence': Trees,
  'Tarihi': History,
  'Diğer': MapPin,
};

const categoryColors: Record<string, string> = {
  'Mekan': 'bg-blue-500',
  'Turizm': 'bg-amber-500',
  'Mağaza': 'bg-purple-500',
  'Eğlence': 'bg-green-500',
  'Tarihi': 'bg-orange-500',
  'Diğer': 'bg-gray-500',
};

export default function CheckinPage() {
  const { address: walletAddress } = useAccount();
  const { user } = useFarcasterAuth();
  const { toast } = useToast();

  const fid = user?.fid?.toString();
  const username = user?.username;

  const [userLocation, setUserLocation] = useState<{ lat: number; lon: number } | null>(null);
  const [locationError, setLocationError] = useState<string | null>(null);
  const [searchRadius, setSearchRadius] = useState(500);
  const [selectedPOI, setSelectedPOI] = useState<POI | null>(null);
  const [showCheckinDialog, setShowCheckinDialog] = useState(false);

  // Get user location
  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setUserLocation({
            lat: position.coords.latitude,
            lon: position.coords.longitude,
          });
          setLocationError(null);
        },
        (error) => {
          console.error('Geolocation error:', error);
          setLocationError('Konum erişimi reddedildi. Lütfen tarayıcı izinlerini kontrol edin.');
        },
        { enableHighAccuracy: true, timeout: 10000, maximumAge: 60000 }
      );
    } else {
      setLocationError('Tarayıcınız konum özelliğini desteklemiyor.');
    }
  }, []);

  // Fetch nearby POIs
  const { data: nearbyData, isLoading: loadingPOIs, refetch: refetchPOIs } = useQuery({
    queryKey: ['/api/places/nearby', userLocation?.lat, userLocation?.lon, searchRadius],
    queryFn: async () => {
      if (!userLocation) return { pois: [], count: 0 };
      const res = await fetch(`/api/places/nearby?lat=${userLocation.lat}&lon=${userLocation.lon}&radius=${searchRadius}`);
      if (!res.ok) throw new Error('Failed to fetch places');
      return res.json();
    },
    enabled: !!userLocation,
    staleTime: 60000,
  });

  // Fetch user's check-in history
  const { data: historyData, isLoading: loadingHistory } = useQuery({
    queryKey: ['/api/checkins/user', walletAddress],
    queryFn: async () => {
      if (!walletAddress) return { checkins: [], count: 0 };
      const res = await fetch(`/api/checkins/user/${walletAddress}?limit=10`);
      if (!res.ok) throw new Error('Failed to fetch history');
      return res.json();
    },
    enabled: !!walletAddress,
  });

  // Fetch user's check-in stats
  const { data: statsData, isLoading: loadingStats } = useQuery({
    queryKey: ['/api/checkins/stats', walletAddress],
    queryFn: async () => {
      if (!walletAddress) return null;
      const res = await fetch(`/api/checkins/stats/${walletAddress}`);
      if (!res.ok) throw new Error('Failed to fetch stats');
      return res.json();
    },
    enabled: !!walletAddress,
  });

  // Check-in mutation
  const checkinMutation = useMutation({
    mutationFn: async (poi: POI) => {
      const response = await apiRequest('POST', '/api/checkins', {
        walletAddress,
        farcasterFid: fid,
        farcasterUsername: username,
        osmId: poi.osmId,
        placeName: poi.name,
        placeCategory: poi.category,
        placeSubcategory: poi.subcategory,
        latitude: poi.lat,
        longitude: poi.lon,
      });
      return response.json();
    },
    onSuccess: (data) => {
      toast({
        title: "Check-in Başarılı!",
        description: `${data.pointsEarned} puan kazandınız!`,
      });
      setShowCheckinDialog(false);
      setSelectedPOI(null);
      queryClient.invalidateQueries({ queryKey: ['/api/checkins/user', walletAddress] });
      queryClient.invalidateQueries({ queryKey: ['/api/checkins/stats', walletAddress] });
    },
    onError: (error: any) => {
      toast({
        title: "Check-in Başarısız",
        description: error.message || "Bir hata oluştu. Lütfen tekrar deneyin.",
        variant: "destructive",
      });
    },
  });

  const handleCheckin = (poi: POI) => {
    if (!walletAddress) {
      toast({
        title: "Cüzdan Gerekli",
        description: "Check-in yapmak için cüzdanınızı bağlayın.",
        variant: "destructive",
      });
      return;
    }
    setSelectedPOI(poi);
    setShowCheckinDialog(true);
  };

  const confirmCheckin = () => {
    if (selectedPOI) {
      checkinMutation.mutate(selectedPOI);
    }
  };

  const refreshLocation = () => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setUserLocation({
            lat: position.coords.latitude,
            lon: position.coords.longitude,
          });
          setLocationError(null);
        },
        (error) => {
          console.error('Geolocation error:', error);
          setLocationError('Konum alınamadı.');
        },
        { enableHighAccuracy: true, timeout: 10000, maximumAge: 0 }
      );
    }
  };

  const pois = nearbyData?.pois || [];
  const checkins = historyData?.checkins || [];
  const stats: CheckinStats | null = statsData;

  const getCategoryIcon = (category: string) => {
    const Icon = categoryIcons[category] || MapPin;
    return Icon;
  };

  return (
    <div className="min-h-screen bg-gradient-to-b from-gray-900 to-black text-white pb-24">
      <div className="max-w-4xl mx-auto px-4 py-6">
        <div className="flex items-center justify-between mb-6">
          <div>
            <h1 className="text-2xl font-bold flex items-center gap-2">
              <MapPinned className="w-6 h-6 text-amber-500" />
              Check-in
            </h1>
            <p className="text-gray-400 text-sm mt-1">Mekanları keşfet, check-in yap, puan kazan!</p>
          </div>
        </div>

        {/* Stats Cards */}
        {walletAddress && (
          <div className="grid grid-cols-3 gap-3 mb-6">
            <Card className="bg-gray-800/50 border-gray-700">
              <CardContent className="p-4 text-center">
                <div className="text-2xl font-bold text-amber-500">
                  {loadingStats ? <Skeleton className="h-8 w-12 mx-auto" /> : stats?.totalCheckins || 0}
                </div>
                <div className="text-xs text-gray-400">Check-in</div>
              </CardContent>
            </Card>
            <Card className="bg-gray-800/50 border-gray-700">
              <CardContent className="p-4 text-center">
                <div className="text-2xl font-bold text-green-500">
                  {loadingStats ? <Skeleton className="h-8 w-12 mx-auto" /> : stats?.uniquePlaces || 0}
                </div>
                <div className="text-xs text-gray-400">Mekan</div>
              </CardContent>
            </Card>
            <Card className="bg-gray-800/50 border-gray-700">
              <CardContent className="p-4 text-center">
                <div className="text-2xl font-bold text-purple-500">
                  {loadingStats ? <Skeleton className="h-8 w-12 mx-auto" /> : stats?.totalPoints || 0}
                </div>
                <div className="text-xs text-gray-400">Puan</div>
              </CardContent>
            </Card>
          </div>
        )}

        {/* Location Status */}
        {locationError ? (
          <Card className="bg-red-900/30 border-red-700 mb-6">
            <CardContent className="p-4">
              <p className="text-red-400 text-sm">{locationError}</p>
              <Button variant="outline" size="sm" className="mt-2" onClick={refreshLocation} data-testid="button-refresh-location">
                <Navigation className="w-4 h-4 mr-2" />
                Tekrar Dene
              </Button>
            </CardContent>
          </Card>
        ) : !userLocation ? (
          <Card className="bg-gray-800/50 border-gray-700 mb-6">
            <CardContent className="p-6 text-center">
              <Loader2 className="w-8 h-8 animate-spin mx-auto text-amber-500 mb-2" />
              <p className="text-gray-400">Konumunuz alınıyor...</p>
            </CardContent>
          </Card>
        ) : (
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-2 text-sm text-gray-400">
              <Navigation className="w-4 h-4 text-green-500" />
              <span>Konumunuz alındı</span>
            </div>
            <div className="flex items-center gap-2">
              <select
                value={searchRadius}
                onChange={(e) => setSearchRadius(Number(e.target.value))}
                className="bg-gray-800 border-gray-700 text-white text-sm rounded-lg px-3 py-1.5"
                data-testid="select-radius"
              >
                <option value={200}>200m</option>
                <option value={500}>500m</option>
                <option value={1000}>1km</option>
                <option value={2000}>2km</option>
              </select>
              <Button variant="outline" size="sm" onClick={refreshLocation} data-testid="button-refresh-location-2">
                <Navigation className="w-4 h-4" />
              </Button>
            </div>
          </div>
        )}

        {/* Nearby Places */}
        <div className="mb-8">
          <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
            <MapPin className="w-5 h-5 text-amber-500" />
            Yakındaki Mekanlar ({pois.length})
          </h2>

          {loadingPOIs ? (
            <div className="space-y-3">
              {[1, 2, 3].map((i) => (
                <Card key={i} className="bg-gray-800/50 border-gray-700">
                  <CardContent className="p-4">
                    <Skeleton className="h-6 w-3/4 mb-2" />
                    <Skeleton className="h-4 w-1/2" />
                  </CardContent>
                </Card>
              ))}
            </div>
          ) : pois.length === 0 ? (
            <Card className="bg-gray-800/50 border-gray-700">
              <CardContent className="p-6 text-center text-gray-400">
                <MapPin className="w-12 h-12 mx-auto mb-3 opacity-50" />
                <p>Yakında mekan bulunamadı.</p>
                <p className="text-sm mt-1">Yarıçapı artırmayı deneyin.</p>
              </CardContent>
            </Card>
          ) : (
            <div className="space-y-3">
              {pois.map((poi: POI) => {
                const Icon = getCategoryIcon(poi.category);
                const colorClass = categoryColors[poi.category] || 'bg-gray-500';

                return (
                  <Card key={poi.osmId} className="bg-gray-800/50 border-gray-700 hover:border-amber-500/50 transition-colors" data-testid={`card-poi-${poi.osmId}`}>
                    <CardContent className="p-4">
                      <div className="flex items-start justify-between">
                        <div className="flex items-start gap-3 flex-1 min-w-0">
                          <div className={`p-2 rounded-lg ${colorClass}`}>
                            <Icon className="w-5 h-5 text-white" />
                          </div>
                          <div className="flex-1 min-w-0">
                            <h3 className="font-semibold text-white truncate">{poi.name}</h3>
                            <div className="flex items-center gap-2 mt-1">
                              <Badge variant="secondary" className="text-xs">
                                {poi.subcategory}
                              </Badge>
                              {poi.cuisine && (
                                <span className="text-xs text-gray-400">{poi.cuisine}</span>
                              )}
                            </div>
                            {poi.address && (
                              <p className="text-xs text-gray-500 mt-1 truncate">{poi.address}</p>
                            )}
                          </div>
                        </div>
                        <Button
                          size="sm"
                          className="bg-amber-500 hover:bg-amber-600 text-black ml-3 shrink-0"
                          onClick={() => handleCheckin(poi)}
                          disabled={!walletAddress}
                          data-testid={`button-checkin-${poi.osmId}`}
                        >
                          <CheckCircle2 className="w-4 h-4 mr-1" />
                          Check-in
                        </Button>
                      </div>
                    </CardContent>
                  </Card>
                );
              })}
            </div>
          )}
        </div>

        {/* Recent Check-ins */}
        {walletAddress && checkins.length > 0 && (
          <div>
            <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
              <History className="w-5 h-5 text-amber-500" />
              Son Check-inler
            </h2>
            <div className="space-y-2">
              {checkins.slice(0, 5).map((checkin: Checkin) => (
                <Card key={checkin.id} className="bg-gray-800/30 border-gray-700/50" data-testid={`card-checkin-${checkin.id}`}>
                  <CardContent className="p-3">
                    <div className="flex items-center justify-between">
                      <div>
                        <p className="font-medium text-sm">{checkin.place_name}</p>
                        <p className="text-xs text-gray-500">
                          {new Date(checkin.created_at).toLocaleDateString('tr-TR')}
                        </p>
                      </div>
                      <Badge className="bg-green-500/20 text-green-400">
                        +{checkin.points_earned} puan
                      </Badge>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          </div>
        )}

        {/* Check-in Confirmation Dialog */}
        <Dialog open={showCheckinDialog} onOpenChange={setShowCheckinDialog}>
          <DialogContent className="bg-gray-900 border-gray-700 text-white">
            <DialogHeader>
              <DialogTitle className="flex items-center gap-2">
                <CheckCircle2 className="w-5 h-5 text-amber-500" />
                Check-in Onayla
              </DialogTitle>
              <DialogDescription className="text-gray-400">
                Bu mekana check-in yapmak üzeresiniz.
              </DialogDescription>
            </DialogHeader>

            {selectedPOI && (
              <div className="py-4">
                <Card className="bg-gray-800/50 border-gray-700">
                  <CardContent className="p-4">
                    <h3 className="font-semibold text-lg">{selectedPOI.name}</h3>
                    <div className="flex items-center gap-2 mt-2">
                      <Badge variant="secondary">{selectedPOI.subcategory}</Badge>
                      <Badge className="bg-amber-500/20 text-amber-400">+10 puan</Badge>
                    </div>
                    {selectedPOI.address && (
                      <p className="text-sm text-gray-400 mt-2">{selectedPOI.address}</p>
                    )}
                  </CardContent>
                </Card>

                <div className="flex gap-3 mt-4">
                  <Button
                    variant="outline"
                    className="flex-1"
                    onClick={() => setShowCheckinDialog(false)}
                    data-testid="button-cancel-checkin"
                  >
                    İptal
                  </Button>
                  <Button
                    className="flex-1 bg-amber-500 hover:bg-amber-600 text-black"
                    onClick={confirmCheckin}
                    disabled={checkinMutation.isPending}
                    data-testid="button-confirm-checkin"
                  >
                    {checkinMutation.isPending ? (
                      <Loader2 className="w-4 h-4 animate-spin mr-2" />
                    ) : (
                      <CheckCircle2 className="w-4 h-4 mr-2" />
                    )}
                    Check-in Yap
                  </Button>
                </div>
              </div>
            )}
          </DialogContent>
        </Dialog>
      </div>
    </div>
  );
}

client/src/pages/travel-ai.tsx.content:
import { useState, useRef, useEffect } from "react";
import { useAccount } from "wagmi";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card } from "@/components/ui/card";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Sparkles, Send, Loader2, Lock } from "lucide-react";

interface WikiImage {
  name: string;
  title: string;
  thumbnailUrl: string | null;
  pageUrl: string | null;
}

interface Message {
  id: string;
  role: "user" | "assistant";
  content: string;
  timestamp: Date;
  images?: WikiImage[];
}

function renderMarkdown(text: string) {
  const parts = text.split(/(\*\*[^*]+\*\*)/g);
  return (
    <>
      {parts.map((part, index) => {
        if (part.startsWith('**') && part.endsWith('**')) {
          return <strong key={index} className="font-bold">{part.slice(2, -2)}</strong>;
        }
        return <span key={index}>{part}</span>;
      })}
    </>
  );
}

interface TravelAIStatus {
  isHolder: boolean;
  queryCount: number;
  remainingFreeQueries: number;
  hasAccess: boolean;
  freeQueryLimit: number;
}

export default function TravelAI() {
  const { address, isConnected } = useAccount();
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState("");
  const scrollRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const queryClient = useQueryClient();

  // Lock body scroll when this page is active
  useEffect(() => {
    const originalStyle = document.body.style.overflow;
    const originalHtmlStyle = document.documentElement.style.overflow;
    const originalTouchAction = document.body.style.touchAction;
    document.body.style.overflow = 'hidden';
    document.documentElement.style.overflow = 'hidden';
    document.body.style.touchAction = 'none';
    document.body.style.position = 'fixed';
    document.body.style.width = '100%';
    document.body.style.height = '100%';

    return () => {
      document.body.style.overflow = originalStyle;
      document.documentElement.style.overflow = originalHtmlStyle;
      document.body.style.touchAction = originalTouchAction;
      document.body.style.position = '';
      document.body.style.width = '';
      document.body.style.height = '';
    };
  }, []);

  // Get Travel AI status (holder status + query count)
  const { data: status, isLoading: isCheckingStatus } = useQuery<TravelAIStatus>({
    queryKey: ["/api/travel-ai/status", address],
    queryFn: async () => {
      const response = await fetch(`/api/travel-ai/status/${address}`);
      if (!response.ok) throw new Error("Failed to check status");
      return response.json();
    },
    enabled: !!address,
  });

  const isHolder = status?.isHolder ?? false;
  const hasAccess = status?.hasAccess ?? false;
  const remainingFreeQueries = status?.remainingFreeQueries ?? 0;

  // Chat mutation with conversation history for context
  const chatMutation = useMutation({
    mutationFn: async ({ message, history }: { message: string; history: Message[] }) => {
      // Format history for API (exclude current message, limit to last 8)
      const chatHistory = history.slice(-8).map(m => ({
        role: m.role,
        content: m.content
      }));

      const response = await fetch("/api/travel-ai/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ message, walletAddress: address, chatHistory }),
      });
      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.error || "Failed to get response");
      }
      return response.json();
    },
    onSuccess: (data) => {
      const assistantMessage: Message = {
        id: Date.now().toString(),
        role: "assistant",
        content: data.response,
        timestamp: new Date(),
        images: data.images || [],
      };
      setMessages((prev) => [...prev, assistantMessage]);
      // Refresh status to update remaining queries
      queryClient.invalidateQueries({ queryKey: ["/api/travel-ai/status", address] });
    },
    onError: (error) => {
      const errorMessage: Message = {
        id: Date.now().toString(),
        role: "assistant",
        content: error.message || "Sorry, an error occurred. Please try again.",
        timestamp: new Date(),
      };
      setMessages((prev) => [...prev, errorMessage]);
    },
  });

  // Auto-scroll to bottom when new messages arrive
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = () => {
    if (!inputValue.trim() || chatMutation.isPending) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: "user",
      content: inputValue.trim(),
      timestamp: new Date(),
    };

    // Pass current messages as history before adding new user message
    const currentHistory = [...messages];
    setMessages((prev) => [...prev, userMessage]);
    chatMutation.mutate({ message: inputValue.trim(), history: currentHistory });
    setInputValue("");
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  // Shared wrapper for all states - viewport locked, no page scroll
  const FixedWrapper = ({ children }: { children: React.ReactNode }) => (
    <div className="flex flex-col bg-black text-white overflow-hidden h-[calc(100dvh-80px)] pb-20" style={{ overscrollBehavior: 'none' }}>
      <div className="flex-1 flex flex-col items-center justify-center min-h-0 overflow-hidden px-4">
        {children}
      </div>
    </div>
  );

  // Not connected state
  if (!isConnected) {
    return (
      <FixedWrapper>
        <Lock className="h-16 w-16 text-gray-500 mb-4" />
        <h1 className="text-2xl font-bold mb-2 text-center">Wallet Connection Required</h1>
        <p className="text-gray-400 max-w-md text-center">
          Please connect your wallet to use the Travel AI feature.
        </p>
      </FixedWrapper>
    );
  }

  // Checking status
  if (isCheckingStatus) {
    return (
      <FixedWrapper>
        <Loader2 className="h-8 w-8 animate-spin text-primary mb-4" />
        <p className="text-gray-400">Checking access...</p>
      </FixedWrapper>
    );
  }

  // No access - daily free queries exhausted and not a holder
  if (!hasAccess) {
    return (
      <FixedWrapper>
        <div className="bg-gradient-to-br from-purple-500/20 to-blue-500/20 p-4 rounded-full mb-4">
          <Sparkles className="h-12 w-12 text-purple-400" />
        </div>
        <h1 className="text-xl font-bold mb-2 text-center">Daily Limit Reached</h1>
        <p className="text-gray-400 max-w-sm mb-4 text-center text-sm">
          You've used your 3 free daily queries. Mint a TravelMint NFT for unlimited access, 
          or come back tomorrow for 3 more free queries!
        </p>
        <div className="flex flex-col gap-2 w-full max-w-xs">
          <Button 
            onClick={() => window.location.href = "/mint"}
            className="bg-gradient-to-r from-purple-500 to-blue-500 hover:from-purple-600 hover:to-blue-600 w-full"
            data-testid="button-mint-nft"
          >
            <Sparkles className="h-4 w-4 mr-2" />
            Mint NFT for Unlimited Access
          </Button>
          <p className="text-gray-500 text-xs text-center">
            Free queries reset daily at midnight UTC
          </p>
        </div>
      </FixedWrapper>
    );
  }

  return (
    <div className="flex flex-col bg-black text-white overflow-hidden h-[calc(100dvh-80px)] pb-20" style={{ overscrollBehavior: 'none' }}>
      <div className="mx-auto flex flex-col w-full max-w-4xl px-3 py-2 gap-2 min-h-0 flex-1 overflow-hidden">
        {/* Header */}
        <div className="flex items-center justify-between shrink-0">
          <div className="flex items-center gap-3">
            <div className="bg-gradient-to-br from-purple-500 to-blue-500 p-2 rounded-lg">
              <Sparkles className="h-5 w-5 text-white" />
            </div>
            <div>
              <h1 className="text-lg font-bold">Travel AI</h1>
              <p className="text-xs text-gray-400">Your personal travel assistant</p>
            </div>
          </div>

          {/* Query counter for non-holders */}
          {!isHolder && (
            <div className="bg-gray-800 px-3 py-1.5 rounded-full">
              <span className="text-xs text-gray-300">
                {remainingFreeQueries} free {remainingFreeQueries === 1 ? 'query' : 'queries'} left
              </span>
            </div>
          )}

          {/* Holder badge */}
          {isHolder && (
            <div className="bg-gradient-to-r from-purple-500/20 to-blue-500/20 px-3 py-1.5 rounded-full border border-purple-500/30">
              <span className="text-xs text-purple-300">Unlimited Access</span>
            </div>
          )}
        </div>

        {/* Chat Area */}
        <Card className="bg-gray-900 border-gray-800 flex flex-col min-h-0 overflow-hidden max-h-[50vh]">
          <div className="flex-1 min-h-0 overflow-y-auto p-3" ref={scrollRef}>
            {messages.length === 0 ? (
              <div className="flex flex-col items-center text-center pt-8">
                <Sparkles className="h-10 w-10 text-purple-400 mb-3" />
                <h2 className="text-base font-semibold mb-2">Hello! 👋</h2>
                <p className="text-gray-400 text-sm max-w-sm">
                  I'm Travel AI, your personal travel assistant. Tell me about the city you want to visit, 
                  and I'll recommend the best places, cafes, and restaurants.
                </p>
              </div>
            ) : (
              <div className="space-y-3">
                {messages.map((message) => (
                  <div
                    key={message.id}
                    className={`flex flex-col ${message.role === "user" ? "items-end" : "items-start"}`}
                  >
                    <div
                      className={`max-w-[85%] rounded-2xl px-3 py-2 ${
                        message.role === "user"
                          ? "bg-purple-600 text-white"
                          : "bg-gray-800 text-gray-100"
                      }`}
                    >
                      <p className="text-sm whitespace-pre-wrap">
                        {message.role === "assistant" ? renderMarkdown(message.content) : message.content}
                      </p>
                    </div>
                    {/* Wikipedia images for places mentioned */}
                    {message.images && message.images.length > 0 && (
                      <div className="flex gap-2 mt-2 max-w-[85%] overflow-x-auto pb-1">
                        {message.images.map((img, idx) => (
                          img.thumbnailUrl && (
                            <a
                              key={idx}
                              href={img.pageUrl || '#'}
                              target="_blank"
                              rel="noopener noreferrer"
                              className="shrink-0 group"
                              data-testid={`link-wiki-image-${idx}`}
                            >
                              <div className="relative rounded-lg overflow-hidden w-20 h-20 bg-gray-700">
                                <img
                                  src={img.thumbnailUrl}
                                  alt={img.name}
                                  className="w-full h-full object-cover transition-transform group-hover:scale-110"
                                  loading="lazy"
                                  data-testid={`img-wiki-thumbnail-${idx}`}
                                />
                                <div className="absolute bottom-0 left-0 right-0 bg-black/70 px-1 py-0.5">
                                  <p className="text-[10px] text-white truncate">{img.name}</p>
                                </div>
                              </div>
                            </a>
                          )
                        ))}
                      </div>
                    )}
                  </div>
                ))}
                {chatMutation.isPending && (
                  <div className="flex justify-start">
                    <div className="bg-gray-800 rounded-2xl px-3 py-2">
                      <div className="flex items-center gap-2">
                        <Loader2 className="h-4 w-4 animate-spin text-purple-400" />
                        <span className="text-sm text-gray-400">Thinking...</span>
                      </div>
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>

          {/* Input Area */}
          <div className="p-3 border-t border-gray-800 shrink-0">
            <div className="flex gap-2">
              <Input
                ref={inputRef}
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
                onKeyPress={handleKeyPress}
                placeholder="Ask about a city or travel tip..."
                className="flex-1 bg-gray-800 border-gray-700 text-white placeholder:text-gray-500 h-10"
                disabled={chatMutation.isPending}
                data-testid="input-chat-message"
              />
              <Button
                onClick={handleSend}
                disabled={!inputValue.trim() || chatMutation.isPending}
                className="bg-purple-600 hover:bg-purple-700 h-10 w-10 p-0"
                data-testid="button-send-message"
              >
                {chatMutation.isPending ? (
                  <Loader2 className="h-4 w-4 animate-spin" />
                ) : (
                  <Send className="h-4 w-4" />
                )}
              </Button>
            </div>
          </div>
        </Card>
      </div>
    </div>
  );
}

server/gemini-service.ts.content:
// Travel AI Service using Google Gemini 2.0 Flash
// Reference: blueprint:javascript_gemini

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.GEMINI_API_KEY || "" });

const TRAVEL_SYSTEM_PROMPT = `You are TravelMint's travel assistant. You help users discover amazing travel destinations.

CRITICAL RULES:
1. ONLY answer what the user specifically asks about - nothing more
2. If user asks about "tourist attractions" - give ONLY tourist attractions (no cafes, no restaurants)
3. If user asks about "cafes" - give ONLY cafes
4. If user asks about "restaurants" - give ONLY restaurants
5. If user asks a general question like "tell me about London" - give a brief overview only
6. Do NOT add extra categories the user didn't ask for
7. Always respond in English

FORMATTING RULES (use markdown):
- Use **bold** for place names and titles
- Use emoji headers for categories
- Keep descriptions short (1-2 sentences max)
- Use bullet points for lists
- Maximum 5 recommendations per category

Example - if user asks "tourist attractions in Barcelona":

🏛️ **Tourist Attractions**

• **Sagrada Familia** - Gaudí's unfinished masterpiece, book tickets in advance
• **Park Güell** - Colorful mosaic park with amazing city views
• **La Rambla** - Famous pedestrian street, great for people watching
• **Gothic Quarter** - Medieval streets and hidden plazas
• **Casa Batlló** - Stunning modernist building by Gaudí

Example - if user asks "best cafes in Paris":

☕ **Cafes**

• **Café de Flore** - Legendary literary café in Saint-Germain
• **Shakespeare and Company Café** - Next to the famous bookshop
• **Claus Paris** - Best breakfast spot in the city`;

interface ChatMessage {
  role: "user" | "assistant";
  content: string;
}

export async function getTravelAdvice(userMessage: string, chatHistory: ChatMessage[] = []): Promise<string> {
  try {
    if (!process.env.GEMINI_API_KEY) {
      throw new Error("GEMINI_API_KEY is not configured");
    }

    // Build contents array with chat history (last 8 messages for context)
    const recentHistory = chatHistory.slice(-8);
    const contents: Array<{ role: "user" | "model"; parts: Array<{ text: string }> }> = [];

    // Add chat history
    for (const msg of recentHistory) {
      contents.push({
        role: msg.role === "user" ? "user" : "model",
        parts: [{ text: msg.content }]
      });
    }

    // Add current message
    contents.push({ role: "user", parts: [{ text: userMessage }] });

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      config: {
        systemInstruction: TRAVEL_SYSTEM_PROMPT,
      },
      contents,
    });

    return response.text || "Sorry, I couldn't generate a response. Please try again.";
  } catch (error) {
    console.error("Gemini API error:", error);
    throw error;
  }
}

